INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'clubs', 'Clubs: cultural: Aurora(ART)club,cinematics,ESports,FOotlights(dance),IMagix(photography),LIterati Society,MUsic,Quorisity,Theatrix Technical: Auv,CS,Epic,Gdsc,Mars,Optica,Robotics,Sae,Tad,Ipd,Amse,Ieee,SSC,', 'Cultural clubs at IIITDM Kancheepuram: Aurora (Art Club), Cinematics, E-Sports, Footlights (Dance), Imagix (Photography), Literati Society, Music, Quorisity (Quiz), Theatrix (Drama). Technical clubs: AUV, CS Club, EPIC, GDSC, MARS, Optica, Robotics, SAE, TAD, IPD, AMSE, IEEE, SSC.', 1, '01/04/26 8:44 pm', '01/04/26 8:44 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'attendance', 'Attendance : 85% mandatory,in case any health issue 75% ( Cerificate Verified by doc in IIItDM)', 'At IIITDM Kancheepuram, 85% attendance is mandatory. In case of health issues, 75% is acceptable with a medical certificate verified by the IIITDM doctor.', 1, '01/04/26 8:47 pm', '01/04/26 8:47 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'wifi', 'Wifi: LAn in HOstels,Wifi also recently installing in each corridors, in academic block some Halls Wifi available', 'IIITDM Kancheepuram has LAN available in hostels. WiFi is recently being installed in hostel corridors. Some halls in the academic block have WiFi.', 1, '01/04/26 8:50 pm', '01/04/26 8:50 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'fests', 'Fests; Savara,Meraki,E- summit (TECH)', 'IIITDM Kancheepuram hosts three main fests: Savara (cultural fest), Meraki, and E-Summit (tech fest).', 1, '01/04/26 8:50 pm', '01/04/26 8:50 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'hostels', 'Hostels: Ashoka,Ahwatha,JAsmine(GIRLS),some blocks are under construction. 2 share, Ashoka 2 & 3 years,aswatha 1 & 4 year', 'IIITDM Kancheepuram has three hostels: Ashoka (2nd and 3rd year boys), Aswatha (1st and 4th year boys), and Jasmine (girls). All rooms are 2-sharing. Some hostel blocks are under construction.', 2, '01/04/26 8:51 pm', '01/04/26 9:47 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'mess', 'Mess: Akshara (Girls+Boys)', 'IIITDM Kancheepuram has one mess called Akshara, which serves both girls and boys.', 1, '01/04/26 8:51 pm', '01/04/26 8:51 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'laundry', 'Laundry: Available near ultimate store,WAshing machines are there hostel ground floors.', 'Laundry service is available near Ultimate Store at IIITDM Kancheepuram. Washing machines are also available on hostel ground floors.', 1, '01/04/26 8:53 pm', '01/04/26 8:53 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'sports', 'Sports : Foot ball,Volley ball,Carroms,badminton,Kho- Kho,Cricket,Running,Kabbadi', 'Sports available at IIITDM Kancheepuram: Football, Volleyball, Carrom, Badminton, Kho-Kho, Cricket, Running/Athletics, and Kabbadi.', 1, '01/04/26 8:54 pm', '01/04/26 8:54 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'canteen', 'Canteen : Ultimate stores,NIght canteen beside to hostels,Cafteria', 'IIITDM Kancheepuram has three food outlets: Ultimate Stores, a night canteen beside the hostels, and a cafeteria.', 1, '01/04/26 8:56 pm', '01/04/26 8:56 pm', 'whatsapp');
