INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'gym', 'Gym : 500 per month for every one', 'IIITDM Kancheepuram has a gym available at Rs 500 per month for everyone.', 1, '01/04/26 8:57 pm', '01/04/26 8:57 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'transport', 'Transport : 515B(drop at kandigai bus stop ,walk 1 km),55D buses from Tambaram railway station,', 'To reach IIITDM Kancheepuram, take Bus 515B which drops at Kandigai bus stop (then 1 km walk to campus), or Bus 55D from Tambaram Railway Station.', 1, '01/04/26 8:20 pm', '01/04/26 8:20 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'restaurants', 'restaurants: Ambrocias,THBB,kalam,KKR,Actc,Bava', 'Nearby restaurants around IIITDM Kancheepuram: Ambrocias, THBB, Kalam, KKR, ACTC, and Bava.', 1, '01/04/26 8:22 pm', '01/04/26 8:22 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'tourist_malls', 'Tourist spots:Vandaloor zoo, Kancheepuram kamakshi Amman Temple, Mahabalipuram. Malls: Marna mall,Vivira mall,Phoenix,AGS cinemas,Mayajaal', 'Tourist spots near IIITDM Kancheepuram: Vandaloor Zoo, Kancheepuram Kamakshi Amman Temple, and Mahabalipuram. Nearby malls and entertainment: Marna Mall, Vivira Mall, Phoenix Mall, AGS Cinemas, and Mayajaal.', 2, '01/04/26 8:31 pm', '01/04/26 8:34 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'ambassador_message', 'climate_language', 'Climate: Mostly sunny. Language : Tamil,english,mostly  telugu people will be there', 'IIITDM Kancheepuram climate is mostly sunny (Chennai region). Languages spoken: Tamil and English. The student population is mostly Telugu-speaking.', 2, '01/04/26 8:35 pm', '01/04/26 8:36 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Kancheepuram', 'document_ocr', 'fee_structure', 'Fee structure B tech. One-time fees Rs 5000 (Admission 500, Certificate 500, Student Welfare 1000, Infrastructure Development 1000, Alumni 500, Library 1000, Cultural 500). Semester fees Rs 85800 (Tuition 81000, Exam 500, Registration 300, Sports 1000, Medical 1000, Student Amenities 2000). Medical Insurance Rs 600 per annum. Hostel fees per semester Rs 38200 (Admission 700, Seat Rent 3500, Maintenance 15000, Dining Advance 17000, Establishment 1000, Development 1000). Grand total first semester Rs 129600. SC/ST/PwD exempted from tuition for 4 years. Hostel compulsory. Income below 1L full tuition remission. Income 1-5L 2/3rd tuition remission.', 'IIITDM Kancheepuram B.Tech fee structure (2024-25 batch): First semester grand total Rs 1,29,600. One-time fees Rs 5,000. Semester fees Rs 85,800 (Tuition Rs 81,000 + Exam Rs 500 + Registration Rs 300 + Sports Rs 1,000 + Medical Rs 1,000 + Student Amenities Rs 2,000). Medical Insurance Rs 600/year. Hostel fees Rs 38,200/semester (Admission Rs 700 + Seat Rent Rs 3,500 + Maintenance Rs 15,000 + Dining Advance Rs 17,000 + Establishment Rs 1,000 + Development Rs 1,000). SC/ST/PwD exempted from tuition for 4 years. Hostel is compulsory. Income below Rs 1 lakh: full tuition remission. Income Rs 1-5 lakh: 2/3rd tuition remission. Dining charges may vary; additional Rs 5,000 for special menu items.', 1, '01/04/26', '01/04/26', 'pdf_ocr');
